// ============================================================
// Input Validation & Sanitization
// ============================================================
const raw = $input.first().json.body || $input.first().json;

// Honeypot check (spam bot detection)
if (raw.website || raw.phone || raw._honeypot) {
  throw new Error('Spam detected: honeypot field filled');
}

// Validate email is present and well-formed
const email = (raw.email || '').trim().toLowerCase();
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!email || !emailRegex.test(email)) {
  throw new Error('Invalid or missing email field');
}

// Sanitize strings: strip HTML/script tags
function sanitize(str) {
  if (typeof str !== 'string') return '';
  return str
    .replace(/<[^>]*>/g, '')
    .replace(/javascript:/gi, '')
    .replace(/on\w+=/gi, '')
    .trim()
    .slice(0, 500); // Max 500 chars
}

const name = sanitize(raw.name);
const company = sanitize(raw.company);
const useCase = sanitize(raw.use_case || raw.useCase).slice(0, 500);

// Derive company domain from email if not provided
const companyDomain = sanitize(raw.company_domain || raw.companyDomain || email.split('@')[1] || '');

return [{
  json: {
    email,
    name,
    company,
    company_domain: companyDomain,
    use_case: useCase,
    _timestamp: new Date().toISOString(),
    _lead_id: `lead_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`
  }
}];

// ============================================================
// A/B Testing: Randomly assign scoring prompt variant
// ============================================================
const variant = Math.random() < 0.5 ? 'A' : 'B';

return [{
  json: {
    ...$input.first().json,
    _ab_test_variant: variant
  }
}];

// ============================================================
// Merge crawled pages into enriched_context
// ============================================================
const items = $input.all();

let allText = '';
const detectedTechs = new Set();
let metaDescription = '';

for (const item of items) {
  const data = item.json;

  // Extract page text (first 3000 chars per page)
  const pageText = (data.text || data.page_text || data.content || '').slice(0, 3000);
  allText += pageText + '\n\n';

  // Collect meta descriptions
  if (data.meta_description) {
    metaDescription = data.meta_description;
  }

  // Collect detected technologies
  if (data.detected_technologies && Array.isArray(data.detected_technologies)) {
    data.detected_technologies.forEach(t => detectedTechs.add(t));
  }
}

// Cap enriched_context at 6000 characters
const enrichedContext = allText.trim().slice(0, 6000);

const leadData = $input.first().json;

return [{
  json: {
    ...leadData,
    enriched_context: enrichedContext,
    meta_description: metaDescription,
    detected_technologies: Array.from(detectedTechs),
    _pages_crawled: items.length
  }
}];

// ============================================================
// Parse LLM JSON response — strips markdown code blocks
// ============================================================
const raw = $input.first().json.response || $input.first().json.content || $input.first().json.message;

if (!raw) {
  throw new Error('No response from OpenClaw scoring node');
}

// Strip markdown code blocks
const cleaned = raw
  .replace(/```json\s*/g, '')
  .replace(/```/g, '')
  .trim();

try {
  const parsed = JSON.parse(cleaned);

  // Validate required fields
  if (typeof parsed.score !== 'number' || parsed.score < 0 || parsed.score > 10) {
    throw new Error(`Invalid score: ${parsed.score}. Must be integer 0-10.`);
  }

  const leadData = $input.first().json;

  return [{
    json: {
      ...leadData,
      score: parsed.score,
      reasoning: parsed.reasoning || '',
      icp_signals: parsed.icp_signals || [],
      disqualifiers: parsed.disqualifiers || []
    }
  }];
} catch (e) {
  throw new Error(`Failed to parse LLM response as JSON: ${e.message}\nRaw: ${cleaned}`);
}

