// ============================================================
// Extract outreach message from OpenClaw response
// ============================================================
const raw = $input.first().json.response || $input.first().json.content || $input.first().json.message;
const outreachMessage = typeof raw === 'string' ? raw.replace(/^```/gm, '').trim() : JSON.stringify(raw);

return [{
  json: {
    ...$input.first().json,
    outreach_message: outreachMessage
  }
}];

